// ─── Бот-имена по рангу ───────────────────────────────────────────────────────

const BOT_NAMES_BY_TIER: Record<RankTier, string[]> = {
  bronze:      ['Алекс', 'Лена', 'Миша', 'Катя', 'Ваня'],
  silver:      ['Дима', 'Аня', 'Коля', 'Света', 'Рома'],
  gold:        ['Артём', 'Юля', 'Максим', 'Наташа', 'Егор'],
  platinum:    ['Виктор', 'Ксения', 'Антон', 'Вика', 'Иван'],
  diamond:     ['Сергей', 'Мария', 'Андрей', 'Ольга', 'Денис'],
  master:      ['Алексей', 'Татьяна', 'Владимир', 'Анна', 'Павел'],
  grandmaster: ['Кирилл', 'Елена', 'Никита', 'Дарья', 'Тимур'],
  legend:      ['Арсений', 'Валерия', 'Глеб', 'Полина', 'Лев'],
};

function pickBotName(tier: RankTier): string {
  const names = BOT_NAMES_BY_TIER[tier];
  return names[Math.floor(Math.random() * names.length)];
}

export async function createBotSession(
  userId: string,
  rankTier: RankTier,
  size: SessionSize
): Promise<string> {
  const level = rankToQuestionLevel(rankTier);
  const questionCount = 7;

  const snap = await col.questions()
    .where('level', '==', level)
    .limit(questionCount * 3)
    .get();

  const all = snap.docs.map(d => d.data() as DuelQuestion);
  const picked = shuffleArray(all).slice(0, questionCount);
  const questionIds = picked.map(q => q.id);

  const sessionId = `bot_${userId}_${Date.now()}`;
  const botCount = size - 1;
  const botIds = Array.from({ length: botCount }, (_, i) => `bot_${i}_${Date.now()}_${i}`);

  const session: DuelSession = {
    id: sessionId,
    type: 'ranked',
    size,
    state: 'countdown',
    rankTier,
    playerIds: [userId],
    botIds,
    questions: questionIds,
    currentQuestionIndex: 0,
    questionStartedAt: null,
    questionTimeoutMs: 15000,
    createdAt: Date.now(),
  };

  const batch = db.batch();

  batch.set(col.sessions().doc(sessionId), session);

  batch.set(col.sessionPlayers().doc(`${sessionId}_${userId}`), {
    sessionId, playerId: userId, isBot: false, score: 0, answers: [],
  });

  botIds.forEach((botId, i) => {
    const name = pickBotName(rankTier);
    batch.set(col.sessionPlayers().doc(`${sessionId}_${botId}`), {
      sessionId, playerId: botId, isBot: true, score: 0, answers: [],
      displayName: name,
    });
  });

  await batch.commit();
  return sessionId;
}
